sql:
SELECT tag_id, incident_id, tag_name
FROM incident_tags
WHERE tag_name LIKE '%Mental Health%';

SELECT it.type_name, tl.level_name
FROM incident_types it
CROSS JOIN threat_levels tl;

SELECT (
    SELECT AVG(level_id) FROM threat_levels
) / (
    SELECT COUNT(*) FROM fleeing_status WHERE status_name = 'Not Fleeing'
) AS threat_level_to_non_fleeing_ratio;

SELECT type_name 
FROM incident_types
WHERE description LIKE '%firearms%';

SELECT type_name
FROM incident_types
WHERE type_id = 1;

SELECT type_name, COUNT(*) AS number_of_incidents
FROM incident_types
GROUP BY type_name;

SELECT tag_name, COUNT(*) AS tag_count
FROM incident_tags
GROUP BY tag_name;

SELECT type_name, COUNT(*) AS incident_count
FROM incident_types
GROUP BY type_name;

SELECT status_id, status_name, description
FROM fleeing_status
WHERE status_id = 0 AND status_name = 'Fleeing';

SELECT COUNT(*) 
FROM incident_types 
WHERE type_id = 0 AND type_name = 'Shooting' AND description = 'Incident involving the use of firearms';

SELECT 
  (SELECT MIN(training_id) FROM officer_training) AS MinTrainingID,
  (SELECT MAX(status_id) FROM fleeing_status) AS MaxStatusID;

SELECT status_name, COUNT(status_id) AS frequency
FROM fleeing_status
WHERE status_id = 0;

SELECT type_name, description
FROM incident_types
WHERE type_id = (SELECT MAX(type_id) FROM incident_types);

